'use client';

import { useEffect, useState } from 'react';
import { motion } from 'framer-motion';
import Link from 'next/link';
import { ContributorCard } from '@/components/contributors/ContributorCard';
import { RefreshCw, Users, Github, AlertCircle } from 'lucide-react';

interface Contributor {
  login: string;
  avatar_url: string;
  html_url: string;
  contributions: number;
}

export default function ContributorsPage() {
  const [contributors, setContributors] = useState<Contributor[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);
  const [isRefreshing, setIsRefreshing] = useState(false);

  const GITHUB_OWNER = 'SKfaizan-786';
  const GITHUB_REPO = 'sentinel-devops-agent';
  // Auto-refresh every 30 minutes
  const AUTO_REFRESH_INTERVAL = 30 * 60 * 1000;

  /**
   * Fetch contributors from GitHub API
   */
  const fetchContributors = async (isAutoRefresh = false) => {
    try {
      if (!isAutoRefresh) {
        setLoading(true);
      }
      setIsRefreshing(true);
      setError(null);

      const response = await fetch(
        `https://api.github.com/repos/${GITHUB_OWNER}/${GITHUB_REPO}/contributors?per_page=100&sort=contributions`,
        {
          headers: {
            'Accept': 'application/vnd.github.v3+json',
            // Add GitHub token from env if available (to increase rate limit)
            ...(process.env.NEXT_PUBLIC_GITHUB_TOKEN && {
              'Authorization': `token ${process.env.NEXT_PUBLIC_GITHUB_TOKEN}`,
            }),
          },
        }
      );

      if (!response.ok) {
        throw new Error(
          `Failed to fetch contributors: ${response.status} ${response.statusText}`
        );
      }

      const data = await response.json();

      const formattedContributors: Contributor[] = data.map(
        (contributor: any) => ({
          login: contributor.login,
          avatar_url: contributor.avatar_url,
          html_url: contributor.html_url,
          contributions: contributor.contributions,
        })
      );

      setContributors(formattedContributors);
      setLastUpdated(new Date());
    } catch (err) {
      console.error('Error fetching contributors:', err);
      setError(
        err instanceof Error ? err.message : 'Failed to fetch contributors'
      );
    } finally {
      setLoading(false);
      setIsRefreshing(false);
    }
  };

  /**
   * Initial fetch and auto-refresh setup
   */
  useEffect(() => {
    fetchContributors();

    // Set up auto-refresh interval
    const intervalId = setInterval(() => {
      fetchContributors(true);
    }, AUTO_REFRESH_INTERVAL);

    return () => clearInterval(intervalId);
  }, []);

  /**
   * Format last updated time
   */
  const formatLastUpdated = (date: Date | null) => {
    if (!date) return 'Never';
    const now = new Date();
    const diffMs = now.getTime() - date.getTime();
    const diffMins = Math.floor(diffMs / 60000);

    if (diffMins < 1) return 'Just now';
    if (diffMins < 60) return `${diffMins}m ago`;

    const diffHours = Math.floor(diffMins / 60);
    if (diffHours < 24) return `${diffHours}h ago`;

    const diffDays = Math.floor(diffHours / 24);
    return `${diffDays}d ago`;
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-950 via-slate-900 to-slate-950 text-slate-200 px-6 py-16">
      {/* Back to Home Button */}
      <div className="max-w-7xl mx-auto mb-8 flex justify-start">
        <Link
          href="/"
          className="inline-block px-5 py-2 rounded-lg bg-cyan-600 hover:bg-cyan-700 text-white font-semibold shadow transition-colors duration-200"
        >
          ← Back to Home
        </Link>
      </div>

      {/* Header Section */}
      <div className="max-w-7xl mx-auto mb-16">
        <motion.div
          initial={{ opacity: 0, y: -30 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6 }}
          className="text-center mb-12"
        >
          <div className="flex items-center justify-center gap-3 mb-4">
            <Users className="w-10 h-10 text-cyan-400" />
            <h1 className="text-4xl md:text-5xl font-bold bg-gradient-to-r from-cyan-400 to-indigo-500 bg-clip-text text-transparent">
              Contributors
            </h1>
          </div>

          <motion.p
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.2 }}
            className="text-lg text-slate-400 max-w-2xl mx-auto"
          >
            Meet the amazing people who make Sentinel DevOps Agent possible.
            Real-time contributor data from our GitHub repository.
          </motion.p>
        </motion.div>

        {/* Stats and Controls */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.3 }}
          className="flex flex-wrap items-center justify-between gap-4 p-4 rounded-xl 
                     bg-slate-800/40 border border-slate-700/50 backdrop-blur-sm"
        >
          <div className="flex items-center gap-3">
            <div className="w-3 h-3 bg-cyan-400 rounded-full animate-pulse"></div>
            <span className="text-sm font-medium text-slate-300">
              {contributors.length} Contributors
            </span>
          </div>

          <div className="flex items-center gap-4">
            <span className="text-sm text-slate-400">
              Last updated: <span className="text-cyan-400 font-semibold">{formatLastUpdated(lastUpdated)}</span>
            </span>

            <button
              onClick={() => fetchContributors()}
              disabled={isRefreshing}
              className="inline-flex items-center gap-2 px-4 py-2 rounded-lg 
                       bg-cyan-600 hover:bg-cyan-700 disabled:bg-slate-700 disabled:cursor-not-allowed
                       text-white font-semibold transition-all duration-300
                       shadow hover:shadow-cyan-500/20"
            >
              <RefreshCw
                className={`w-4 h-4 ${isRefreshing ? 'animate-spin' : ''}`}
              />
              {isRefreshing ? 'Refreshing...' : 'Refresh'}
            </button>

            <Link
              href={`https://github.com/${GITHUB_OWNER}/${GITHUB_REPO}`}
              target="_blank"
              rel="noopener noreferrer"
              className="inline-flex items-center gap-2 px-4 py-2 rounded-lg 
                       bg-slate-700 hover:bg-slate-600 text-white font-semibold 
                       transition-all duration-300 shadow hover:shadow-slate-700/50"
            >
              <Github className="w-4 h-4" />
              View on GitHub
            </Link>
          </div>
        </motion.div>
      </div>

      {/* Loading State */}
      {loading && (
        <div className="max-w-7xl mx-auto">
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
            {Array.from({ length: 12 }).map((_, i) => (
              <div
                key={i}
                className="animate-pulse p-6 rounded-2xl bg-slate-800/50 
                          border border-slate-700/50 h-64"
              >
                <div className="space-y-4">
                  <div className="w-20 h-20 mx-auto rounded-full bg-slate-700/50"></div>
                  <div className="h-4 bg-slate-700/50 rounded mx-auto w-24"></div>
                  <div className="h-3 bg-slate-700/50 rounded mx-auto w-20"></div>
                  <div className="h-8 bg-slate-700/50 rounded mx-auto w-28 mt-4"></div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Error State */}
      {error && !loading && (
        <motion.div
          initial={{ opacity: 0, scale: 0.95 }}
          animate={{ opacity: 1, scale: 1 }}
          className="max-w-2xl mx-auto p-6 rounded-xl bg-red-950/30 border border-red-900/50 backdrop-blur-sm"
        >
          <div className="flex items-start gap-4">
            <AlertCircle className="w-6 h-6 text-red-400 flex-shrink-0 mt-0.5" />
            <div>
              <h3 className="text-lg font-bold text-red-300 mb-2">
                Failed to Load Contributors
              </h3>
              <p className="text-red-200 mb-4">{error}</p>
              <button
                onClick={() => fetchContributors()}
                className="px-4 py-2 rounded-lg bg-red-600 hover:bg-red-700 
                         text-white font-semibold transition-colors duration-300"
              >
                Try Again
              </button>
            </div>
          </div>
        </motion.div>
      )}

      {/* Contributors Grid */}
      {!loading && !error && contributors.length > 0 && (
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ staggerChildren: 0.05 }}
          className="max-w-7xl mx-auto"
        >
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
            {contributors.map((contributor, index) => (
              <ContributorCard
                key={contributor.login}
                {...contributor}
                index={index}
              />
            ))}
          </div>
        </motion.div>
      )}

      {/* Empty State */}
      {!loading && !error && contributors.length === 0 && (
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          className="max-w-2xl mx-auto text-center py-16"
        >
          <Users className="w-16 h-16 text-slate-600 mx-auto mb-4" />
          <h3 className="text-xl font-bold text-slate-300 mb-2">
            No Contributors Found
          </h3>
          <p className="text-slate-400">
            Unable to fetch contributors at this time. Please try again later.
          </p>
        </motion.div>
      )}

      {/* Footer Info */}
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: 0.5 }}
        className="max-w-7xl mx-auto mt-20 text-center text-sm text-slate-400"
      >
        <p>
          This page automatically updates every 30 minutes with the latest contributor
          data from{' '}
          <Link
            href={`https://github.com/${GITHUB_OWNER}/${GITHUB_REPO}`}
            target="_blank"
            rel="noopener noreferrer"
            className="text-cyan-400 hover:text-cyan-300 underline transition-colors"
          >
            GitHub
          </Link>
          .
        </p>
      </motion.div>
    </div>
  );
}

"use client";

import { DashboardHeader } from "@/components/layout/DashboardHeader";
import { IncidentCard } from "@/components/dashboard/IncidentCard";
import { Suspense, useState, useCallback, useEffect } from "react";
import { useSearchParams, useRouter } from "next/navigation";
import { Activity, Clock, AlertCircle, FileWarning } from "lucide-react";
import { IncidentTable } from "@/components/incidents/IncidentTable";
import { IncidentFilters } from "@/components/incidents/IncidentFilters";
import { IncidentSearch } from "@/components/incidents/IncidentSearch";
import { IncidentExport } from "@/components/incidents/IncidentExport";
import { TableSkeleton } from "@/components/incidents/TableSkeleton";
import { Pagination } from "@/components/common/Pagination";
import { useIncidentHistory, FilterState, SortConfig } from "@/hooks/useIncidentHistory";

const defaultFilters: FilterState = {
    services: [],
    severities: [],
    statuses: [],
    dateRange: { start: null, end: null },
};

function IncidentsContent() {
    const router = useRouter();
    const searchParams = useSearchParams();

    // Initialize state from URL params
    const [filters, setFilters] = useState<FilterState>(() => {
        const services = searchParams.get("services")?.split(",").filter(Boolean) || [];
        const severities = (searchParams.get("severities")?.split(",").filter(Boolean) || []) as FilterState["severities"];
        const statuses = (searchParams.get("statuses")?.split(",").filter(Boolean) || []) as FilterState["statuses"];
        const startDate = searchParams.get("start");
        const endDate = searchParams.get("end");

        return {
            services,
            severities,
            statuses,
            dateRange: {
                start: startDate ? new Date(startDate) : null,
                end: endDate ? new Date(endDate) : null,
            },
        };
    });

    const [search, setSearch] = useState(searchParams.get("q") || "");
    const [sortConfig, setSortConfig] = useState<SortConfig>(() => {
        const sortKey = searchParams.get("sortBy") || "timestamp";
        const sortDir = searchParams.get("sortDir") || "desc";
        return { key: sortKey as SortConfig["key"], direction: sortDir as SortConfig["direction"] };
    });
    const [page, setPage] = useState(Number(searchParams.get("page")) || 1);
    const [pageSize, setPageSize] = useState(Number(searchParams.get("pageSize")) || 10);

    const { incidents, isLoading, totalCount, totalActive, totalCritical, allServices } = useIncidentHistory({
            filters,
            search,
            sort: sortConfig,
            page,
            pageSize,
        });

    // Sync URL with state
    useEffect(() => {
        const params = new URLSearchParams();

        if (search) params.set("q", search);
        if (filters.services.length) params.set("services", filters.services.join(","));
        if (filters.severities.length) params.set("severities", filters.severities.join(","));
        if (filters.statuses.length) params.set("statuses", filters.statuses.join(","));
        if (filters.dateRange.start) params.set("start", filters.dateRange.start.toISOString().split("T")[0]);
        if (filters.dateRange.end) params.set("end", filters.dateRange.end.toISOString().split("T")[0]);
        if (sortConfig.key !== "timestamp") params.set("sortBy", sortConfig.key);
        if (sortConfig.direction !== "desc") params.set("sortDir", sortConfig.direction);
        if (page > 1) params.set("page", String(page));
        if (pageSize !== 10) params.set("pageSize", String(pageSize));

        const queryString = params.toString();
        const newUrl = queryString ? `?${queryString}` : "";

        // Only update if different to avoid infinite loops
        if (newUrl !== (window.location.search || "")) {
            router.replace(`/dashboard/incidents${newUrl}`, { scroll: false });
        }
    }, [filters, search, sortConfig, page, pageSize, router]);

    const handleSort = useCallback((key: string) => {
        setSortConfig((prev) => ({
            key: key as SortConfig["key"],
            direction: prev.key === key && prev.direction === "desc" ? "asc" : "desc",
        }));
        setPage(1); // Reset to first page on sort change
    }, []);

    const handleClearFilters = useCallback(() => {
        setFilters(defaultFilters);
        setSearch("");
        setPage(1);
    }, []);

    const handlePageSizeChange = useCallback((newSize: number) => {
        setPageSize(newSize);
        setPage(1);
    }, []);

    const handleFilterChange = useCallback((newFilters: FilterState) => {
        setFilters(newFilters);
        setPage(1);
    }, []);

    const totalPages = Math.ceil(totalCount / pageSize);

    return (
        <div className="w-full max-w-full overflow-x-hidden">
            <div className="container mx-auto max-w-7xl px-2 sm:px-4 lg:px-6 pb-20 space-y-4 sm:space-y-6">
                {/* Header */}
                <div className="flex flex-col lg:flex-row lg:items-center lg:justify-between gap-4 px-2 sm:px-0">
                    <div>
                        <h1 className="text-3xl font-bold tracking-tight text-white">Incident History</h1>
                        <p className="text-muted-foreground">
                            Comprehensive log of all system incidents and agent remediations.
                        </p>
                    </div>
                    <IncidentExport incidents={incidents} disabled={isLoading} />
                </div>

                {/* Stats Cards */}
                <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-4 gap-3 sm:gap-4">
                    <div className="p-3 sm:p-4 bg-white/5 border border-white/5 rounded-xl">
                        <div className="flex items-center gap-2 text-muted-foreground mb-1">
                            <AlertCircle className="h-4 w-4" />
                            <span className="text-xs uppercase tracking-wider font-semibold">Total</span>
                        </div>
                        <div className="text-2xl font-bold text-white">{totalCount}</div>
                    </div>
                    <div className="p-3 sm:p-4 bg-white/5 border border-white/5 rounded-xl">
                        <div className="flex items-center gap-2 text-muted-foreground mb-1">
                            <Activity className="h-4 w-4" />
                            <span className="text-xs uppercase tracking-wider font-semibold">Active</span>
                        </div>
                        <div className="text-2xl font-bold text-yellow-400">{totalActive}</div>
                    </div>
                    <div className="p-3 sm:p-4 bg-white/5 border border-white/5 rounded-xl">
                        <div className="flex items-center gap-2 text-muted-foreground mb-1">
                            <FileWarning className="h-4 w-4" />
                            <span className="text-xs uppercase tracking-wider font-semibold">Critical</span>
                        </div>
                        <div className="text-2xl font-bold text-red-400">{totalCritical}</div>
                    </div>
                    <div className="p-3 sm:p-4 bg-white/5 border border-white/5 rounded-xl overflow-hidden">
                        <div className="flex items-center gap-2 text-muted-foreground mb-1">
                            <Clock className="h-4 w-4 shrink-0" />
                            <span className="text-xs uppercase tracking-wider font-semibold">MTTR</span>
                        </div>
                        <div className="text-2xl font-bold text-white truncate">
                            {(() => {
                                const resolvedIncidents = incidents.filter(
                                    (i) => i.status === "resolved" && i.duration !== "N/A"
                                );
                                if (resolvedIncidents.length === 0) return "—";

                                let totalSeconds = 0;
                                let count = 0;

                                resolvedIncidents.forEach((inc) => {
                                    const mMatch = inc.duration.match(/(\d+)m/);
                                    const sMatch = inc.duration.match(/(\d+)s/);
                                    let seconds = 0;
                                    if (mMatch) seconds += parseInt(mMatch[1]) * 60;
                                    if (sMatch) seconds += parseInt(sMatch[1]);

                                    if (seconds > 0) {
                                        totalSeconds += seconds;
                                        count++;
                                    }
                                });

                                if (count === 0) return "—";
                                const avgSeconds = Math.round(totalSeconds / count);
                                const avgM = Math.floor(avgSeconds / 60);
                                const avgS = avgSeconds % 60;

                                if (avgM > 0) return `${avgM}m ${avgS}s`;
                                return `${avgS}s`;
                            })()}
                        </div>
                    </div>
                </div>

                {/* Search */}
                <IncidentSearch value={search} onChange={setSearch} />

                {/* Filters */}
                <IncidentFilters
                    filters={filters}
                    onChange={handleFilterChange}
                    onClear={handleClearFilters}
                    services={allServices}
                />

                {/* Results count */}
                <div className="flex items-center justify-between">
                    <h2 className="text-lg font-semibold text-white">
                        {totalCount} Incident{totalCount !== 1 && "s"} Found
                    </h2>
                </div>

                {/* Table or Empty/Loading State */}
                {isLoading ? (
                    <TableSkeleton rows={pageSize} />
                ) : incidents.length > 0 ? (
                    <>
                        <IncidentTable incidents={incidents} onSort={handleSort} sortConfig={sortConfig} />
                        {totalPages > 1 && (
                            <Pagination
                                currentPage={page}
                                totalPages={totalPages}
                                totalCount={totalCount}
                                pageSize={pageSize}
                                onPageChange={setPage}
                                onPageSizeChange={handlePageSizeChange}
                            />
                        )}
                    </>
                ) : (
                    <div className="text-center py-20 bg-white/5 border border-white/10 rounded-xl border-dashed">
                        <FileWarning className="h-12 w-12 mx-auto text-muted-foreground/50 mb-4" />
                        <p className="text-muted-foreground mb-2">No incidents found matching your criteria.</p>
                        <button
                            onClick={handleClearFilters}
                            className="text-primary text-sm hover:underline"
                        >
                            Clear all filters
                        </button>
                    </div>
                )}
            </div>
        </div>
    );
}

function IncidentsLoadingFallback() {
    return (
        <div className="w-full max-w-full overflow-x-hidden">
            <div className="container mx-auto max-w-7xl px-2 sm:px-4 lg:px-6 pb-20 space-y-4 sm:space-y-6">
                <div className="px-2 sm:px-0">
                    <h1 className="text-3xl font-bold tracking-tight text-white">Incident History</h1>
                    <p className="text-muted-foreground">
                        Comprehensive log of all system incidents and agent remediations.
                    </p>
                </div>
                <TableSkeleton rows={10} />
            </div>
        </div>
    );
}

export default function IncidentsPage() {
    return (
        <Suspense fallback={<IncidentsLoadingFallback />}>
            <IncidentsContent />
        </Suspense>
    );
}

'use client';

import { motion } from 'framer-motion';
import Link from 'next/link';
import { Github } from 'lucide-react';

interface ContributorCardProps {
  login: string;
  avatar_url: string;
  html_url: string;
  contributions: number;
  index: number;
}

/**
 * Individual contributor card component
 */
export function ContributorCard({
  login,
  avatar_url,
  html_url,
  contributions,
  index,
}: ContributorCardProps) {
  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      whileInView={{ opacity: 1, y: 0 }}
      transition={{ delay: index * 0.05, duration: 0.4 }}
      viewport={{ once: true }}
      whileHover={{ y: -8, scale: 1.02 }}
      className="group relative h-full"
    >
      <Link href={html_url} target="_blank" rel="noopener noreferrer">
        <div className="relative h-full p-6 rounded-2xl bg-gradient-to-br from-slate-800/50 to-slate-900/50 
                        border border-slate-700/50 backdrop-blur-sm
                        hover:border-cyan-500/50 transition-all duration-300
                        shadow-lg hover:shadow-cyan-500/20 overflow-hidden">
          
          {/* Background glow effect */}
          <div className="absolute inset-0 rounded-2xl bg-gradient-to-br from-cyan-500/0 via-indigo-500/0 to-cyan-500/0 
                          group-hover:from-cyan-500/10 group-hover:via-indigo-500/10 group-hover:to-cyan-500/10 
                          transition-all duration-500"></div>

          {/* Content */}
          <div className="relative z-10 flex flex-col items-center text-center space-y-4">
            {/* Avatar */}
            <motion.div
              whileHover={{ scale: 1.1 }}
              className="relative"
            >
              <img
                src={avatar_url}
                alt={login}
                className="w-20 h-20 rounded-full border-2 border-cyan-500/50 
                           group-hover:border-cyan-400 transition-colors duration-300
                           shadow-lg"
              />
              <div className="absolute -bottom-1 -right-1 bg-cyan-500 rounded-full p-2">
                <Github className="w-4 h-4 text-white" />
              </div>
            </motion.div>

            {/* Username */}
            <div>
              <h3 className="text-lg font-bold text-white group-hover:text-cyan-400 
                           transition-colors duration-300">
                {login}
              </h3>
              <p className="text-sm text-cyan-400 mt-1 flex items-center justify-center gap-1">
                <span className="inline-block w-2 h-2 bg-cyan-400 rounded-full"></span>
                {contributions} {contributions === 1 ? 'contribution' : 'contributions'}
              </p>
            </div>

            {/* View Profile Badge */}
            <div className="pt-2">
              <span className="inline-block px-3 py-1 text-xs font-semibold 
                             bg-cyan-500/20 text-cyan-300 rounded-full
                             group-hover:bg-cyan-500/40 transition-colors duration-300">
                View Profile →
              </span>
            </div>

            {/* Stats Bar */}
            <div className="w-full pt-2 mt-2 border-t border-slate-700/50">
              <div className="flex justify-center items-center gap-2 text-xs text-slate-400">
                <span className="font-semibold text-cyan-400">{contributions}</span>
                <span>contributions</span>
              </div>
            </div>
          </div>
        </div>
      </Link>
    </motion.div>
  );
}

"use client";

import Link from "next/link";
import { Button } from "@/components/common/Button";
import { SentinelLogo } from "@/components/common/SentinelLogo";
import { useEffect, useState, useRef } from "react";
import { cn } from "@/lib/utils";
import { useWebSocketContext } from "@/lib/WebSocketContext";
import { Wifi, WifiOff, Info, Menu, X } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";

export function Header() {
